#include <bits/stdc++.h>    using namespace std; // --- FAST I/O & SHORTCUTS ---using ll = long long;using vll = vector<long long>;using vi = vector<int>;using pii = pair<int, int>; // Constantsconst ll MOD = 1e9 + 7;const ll INF = 1e18; // --- LOGIC ---void solve() {    int n,k,x,b,c;    cin >> n >> k >> x;    if(x!=1){        cout << "YES\n";        cout << n << "\n";        for(int i=0; i<n; i++){            cout << 1 << " ";        }        cout << "\n";    } else {        if(k==1){            cout << "NO\n";        } else if(k==2){            if(n%2==0){                cout << "YES\n";                cout << n/2 << "\n";                for(int i=0; i<n/2; i++){                    cout << 2 << " ";                }                cout << "\n";            } else {                cout << "NO\n";            }        } else {            cout << "YES\n";            if(n%2==0){                cout << n/2 << "\n";                for(int i=0; i<n/2; i++){                                        cout << 2 << " ";                }                cout << "\n";            } else {                cout << (n-3)/2 + 1 << "\n";                cout << 3 << " ";                for(int i=0; i<(n-3)/2; i++){                    cout << 2 << " ";                }                cout << "\n";            }        }    } } // --- MAIN DRIVER ---int main() {    // Fast I/O: 10x faster input reading    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int T = 1;    cin >> T; // Comment this out if problem has NO test cases    while (T--) {        solve();    }    return 0;}